import {
	useBlockProps,
	InspectorControls,
	InnerBlocks,
	URLInput,
} from '@wordpress/block-editor';

import './editor.scss';

import {
	Button,
	PanelBody,
	Popover,
	TabPanel,
	ToggleControl,
} from '@wordpress/components';
import settingsIcon from '../assests/setting.svg';
import paletteIcon from '../assests/palette.svg';
import ChildItemStyle from './ChildItemStyle.js';
import resetIcon from '../assests/reset.svg';
import { getBlockStyles } from '../utils/style.js';
import { useParentAttributes } from '../hooks/useParentAttributes.js';
import { useEffect, useRef, useState } from '@wordpress/element';
import editIcon from '../assests/edit-icon.svg';

// This is the checkmark icon from your image

export default function Edit( { attributes, setAttributes, clientId } ) {
	const [ openModalId, setOpenModalId ] = useState( null );
	const toggleModal = ( id ) => {
		setOpenModalId( ( prev ) => ( prev === id ? null : id ) );
	};
	const isModalOpen = ( id ) => openModalId === id;
	const closeAllModals = () => setOpenModalId( null );

	const childStyle = getBlockStyles( attributes );

	const parentLayout = useParentAttributes( clientId );

	// const prevGrand = useRef( null );

	// useEffect( () => {
	// 	const current = parentLayout || {};

	// 	if ( prevGrand.current === null ) {
	// 		prevGrand.current = { ...current };
	// 		return;
	// 	}

	// 	const previous = prevGrand.current || {};

	// 	// Find which grandparent keys actually changed
	// 	const changedKeys = Object.keys( current ).filter(
	// 		( key ) => current[ key ] !== previous[ key ]
	// 	);

	// 	if ( changedKeys.length === 0 ) {
	// 		return;
	// 	}

	// 	const updates = {};

	// 	changedKeys.forEach( ( key ) => {
	// 		// Only update child if value truly differs
	// 		if ( attributes[ key ] !== current[ key ] ) {
	// 			updates[ key ] = current[ key ];
	// 		}
	// 	} );

	// 	if ( Object.keys( updates ).length > 0 ) {
	// 		setAttributes( updates );
	// 	}

	// 	// Update snapshot memory
	// 	prevGrand.current = { ...current };
	// }, [ parentLayout ] );

	const blockProps = useBlockProps( {
		style: {
			...childStyle, // This spreads all properties from getChildBlockStyles
		},
	} );

	const renderTabContent = ( tab ) => {
		if ( tab.name === 'settings' ) {
			return (
				<>
					<div className="url-link-container">
						<URLInput
							className="url-container"
							label="Add Link"
							value={ attributes?.url }
							onChange={ ( nextUrl ) =>
								setAttributes( { url: nextUrl } )
							}
							placeholder="Type or paste your URL"
						/>
						<Button
							className="pencil-edit-button"
							icon={
								<img
									src={ editIcon }
									alt={ __( 'Edit', 'icon-picker' ) }
									style={ {
										width: '36px',
										height: '36px',
									} }
								/>
							}
							onClick={ () => toggleModal( 'link' ) }
						/>

						{ isModalOpen( 'link' ) && (
							<Popover
								onClose={ closeAllModals }
								placement="bottom"
								offset={ 10 }
							>
								<div className="link-popover-container">
									<ToggleControl
										className="my-custom-troggle"
										label={ __(
											'open in new tab',
											'icon-picker'
										) }
										checked={ attributes?.newTab }
										onChange={ ( value ) =>
											setAttributes( { newTab: value } )
										}
									/>
									<ToggleControl
										className="my-custom-troggle"
										label={ __(
											'Mark As No Follow',
											'icon-picker'
										) }
										checked={ attributes?.noFollow }
										onChange={ ( value ) =>
											setAttributes( { noFollow: value } )
										}
									/>
									<URLInput
										className="custom-link-relation"
										label="Custom Link Relation"
										value={ attributes?.url }
										onChange={ ( nextUrl ) =>
											setAttributes( { url: nextUrl } )
										}
									/>
									<p className="extra-text">
										Enter one or more link Relations (e.g.,
										nofollow noopener sponsored), separated
										by spaces.
									</p>
								</div>
							</Popover>
						) }
					</div>
				</>
			);
		}

		if ( tab.name === 'styles' ) {
			return (
				<>
					<ChildItemStyle
						attributes={ attributes }
						setAttributes={ setAttributes }
						resetIcon={ resetIcon }
					/>
				</>
			);
		}

		// NEVER return null here
		return null;
	};

	const TEMPLATE = [
		[ 'create-block/icon-picker', {} ],
		[ 'create-block/advanced-text', { placeholder: 'List Text Here' } ],
	];

	return (
		<>
			<InspectorControls>
				<PanelBody title={ __( 'Icon List', 'icon-list' ) }>
					<TabPanel
						className="my-custom-tabs"
						activeClass="is-active"
						tabs={ [
							{
								name: 'settings',
								title: (
									<>
										<img
											src={ settingsIcon }
											width={ 16 }
											height={ 16 }
											alt="Settings"
										/>
										{ __( 'Settings', 'icon-list' ) }
									</>
								),
								className: 'tab-settings',
							},
							{
								name: 'styles',
								title: (
									<>
										<img
											src={ paletteIcon }
											width={ 16 }
											height={ 16 }
											alt="Palette"
										/>
										{ __( 'Style', 'icon-list' ) }
									</>
								),
								className: 'tab-styles',
							},
						] }
					>
						{ renderTabContent }
					</TabPanel>
				</PanelBody>
			</InspectorControls>
			<div { ...blockProps }>
				<InnerBlocks
					allowedBlocks={ [
						'create-block/icon-picker',
						'create-block/advanced-text',
					] }
					template={ TEMPLATE }
				/>
			</div>
		</>
	);
}
